import React, { useState } from 'react';

// --- STİLLER (Garantili Yöntem) ---
const colors = {
  butterYellow: '#FEFAE0',
  softPink: '#F8AD9D',
  softBeige: '#FAEDCD',
  softGreen: '#B5E48C',
  white: '#FFFFFF',
  text: '#6B705C'
};

const commonStyles = {
  container: { backgroundColor: colors.butterYellow, minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: 'sans-serif' },
  card: { backgroundColor: colors.white, width: '100%', maxWidth: '500px', padding: '40px', borderRadius: '40px', boxShadow: '0 15px 30px rgba(0,0,0,0.05)', textAlign: 'center' },
  button: { width: '100%', padding: '15px', backgroundColor: colors.softPink, color: 'white', border: 'none', borderRadius: '15px', fontWeight: 'bold', cursor: 'pointer', marginTop: '20px' }
};

// --- 1. SAYFA: GİRİŞ ---
const AuthPage = ({ onNext }) => (
  <div style={commonStyles.container}>
    <div style={commonStyles.card}>
      <h1 style={{ color: colors.softPink, fontSize: '32px' }}>Planly 🌸</h1>
      <p style={{ color: '#A5A5A5', marginBottom: '20px' }}>Tekrar hoş geldin!</p>
      <input style={{ width: '100%', padding: '15px', marginBottom: '10px', borderRadius: '12px', border: '1px solid #eee' }} type="email" placeholder="E-posta" />
      <input style={{ width: '100%', padding: '15px', marginBottom: '10px', borderRadius: '12px', border: '1px solid #eee' }} type="password" placeholder="Şifre" />
      <button style={commonStyles.button} onClick={onNext}>Giriş Yap ✨</button>
    </div>
  </div>
);

// --- 2. SAYFA: SINAV SEÇİMİ (ONBOARDING) ---
const OnboardingPage = ({ onNext }) => {
  const exams = ['YKS', 'KPSS', 'DGS', 'LGS'];
  const [selected, setSelected] = useState('');

  return (
    <div style={commonStyles.container}>
      <div style={commonStyles.card}>
        <h2 style={{ color: colors.text, marginBottom: '10px' }}>Hedefini Seç 🎯</h2>
        <p style={{ color: '#A5A5A5', marginBottom: '30px' }}>Hangi sınava hazırlanıyoruz?</p>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
          {exams.map(exam => (
            <div 
              key={exam}
              onClick={() => setSelected(exam)}
              style={{
                padding: '25px',
                borderRadius: '20px',
                border: selected === exam ? `3px solid ${colors.softPink}` : `1px solid ${colors.softBeige}`,
                backgroundColor: selected === exam ? '#FFF5F5' : 'white',
                cursor: 'pointer',
                fontWeight: 'bold',
                color: selected === exam ? colors.softPink : colors.text,
                transition: '0.3s'
              }}
            >
              {exam}
            </div>
          ))}
        </div>

        <button 
          style={{ ...commonStyles.button, backgroundColor: selected ? colors.softPink : '#ddd' }} 
          disabled={!selected}
          onClick={onNext}
        >
          Devam Et (Konuları Seç) →
        </button>
      </div>
    </div>
  );
};

// --- ANA UYGULAMA YÖNETİCİSİ ---
function App() {
  const [step, setStep] = useState(1);

  return (
    <>
      {step === 1 && <AuthPage onNext={() => setStep(2)} />}
      {step === 2 && <OnboardingPage onNext={() => setStep(3)} />}
      {step === 3 && (
        <div style={commonStyles.container}>
          <div style={commonStyles.card}>
            <h2 style={{ color: colors.softGreen }}>Harika! 🌿</h2>
            <p>3. Adım: Takvim ve Arkadaşlarla Çalışma sayfası yolda...</p>
          </div>
        </div>
      )}
    </>
  );
}

export default App;
